//#region src/syntax/kotlin/kotlin-generator-suite.ts
/**
* Creates a Kotlin generator suite with composed dependencies
*/
function createKotlinGeneratorSuite(options = {}) {
	const { typeMappingOptions = {}, codeEmitterOptions = {} } = options;
	const typeMapper = createKotlinTypeMapper(typeMappingOptions);
	const codeEmitter = createKotlinCodeEmitter(codeEmitterOptions);
	const protocolGenerator = createKotlinProtocolGenerator({
		typeMapper,
		codeEmitter
	});
	const structGenerator = createKotlinStructGenerator({
		typeMapper,
		codeEmitter
	});
	const methodGenerator = createKotlinMethodGenerator({ typeMapper });
	const deps = {
		typeMapper,
		codeEmitter,
		protocolGenerator,
		structGenerator,
		methodGenerator,
		bridgeGenerator: createKotlinBridgeGenerator({
			codeEmitter,
			methodGenerator
		})
	};
	/**
	* Generate interface/spec for a module
	*/
	function generateInterface(module) {
		return protocolGenerator.generateLibraryModuleInterface(module);
	}
	/**
	* Generate data class types for a module
	*/
	function generateDataClasses(module) {
		return structGenerator.generateModuleTypes(module);
	}
	/**
	* Generate bridge implementation files
	*/
	function generateBridge(_modules) {
		return {
			bridgeModule: "// Use AndroidPlatform.generateFiles() for full bridge generation",
			bridgeImplementation: "// Use AndroidPlatform.generateFiles() for full bridge generation",
			buildGradle: "// Use AndroidPlatform.generateFiles() for full bridge generation"
		};
	}
	/**
	* Generate complete Kotlin implementation for a module
	*/
	function generateKotlinImplementation(_module) {
		return "// Use AndroidPlatform.generateFiles() for full implementation";
	}
	/**
	* Generate library mode interface (public API)
	*/
	function generateLibraryInterface(module) {
		return protocolGenerator.generateLibraryModuleInterface(module);
	}
	/**
	* Generate library mode data classes
	*/
	function generateLibraryDataClasses(module) {
		return structGenerator.generateModuleTypes(module);
	}
	return {
		deps,
		generateInterface,
		generateDataClasses,
		generateBridge,
		generateKotlinImplementation,
		generateLibraryInterface,
		generateLibraryDataClasses
	};
}

